from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END

class RouterState(TypedDict):
    message: str
    intent: str
    confidence: float
    response: str

def classify(state: RouterState) -> RouterState:
    result = classifier.invoke(state["message"])
    return {"intent": result.intent, "confidence": result.confidence}

def route(state: RouterState) -> Literal["faq", "support", "sales", "other"]:
    if state["confidence"] < 0.6:
        return "other"       # low confidence → fallback
    return state["intent"]

def handle_faq(state: RouterState) -> RouterState:
    reply = faq_chain.invoke({"question": state["message"]})
    return {"response": reply}

def handle_support(state: RouterState) -> RouterState:
    reply = support_chain.invoke({"issue": state["message"]})
    return {"response": reply}

def handle_sales(state: RouterState) -> RouterState:
    reply = sales_chain.invoke({"query": state["message"]})
    return {"response": reply}

def handle_other(state: RouterState) -> RouterState:
    return {"response": "I'm not sure how to help with that — could you rephrase?"}

builder = StateGraph(RouterState)
builder.add_node("classify", classify)
builder.add_node("faq", handle_faq)
builder.add_node("support", handle_support)
builder.add_node("sales", handle_sales)
builder.add_node("other", handle_other)

builder.set_entry_point("classify")
builder.add_conditional_edges("classify", route)
builder.add_edge("faq", END)
builder.add_edge("support", END)
builder.add_edge("sales", END)
builder.add_edge("other", END)

graph = builder.compile()

class SupportSubcategory(BaseModel):
    subcategory: Literal["billing", "technical", "account", "other"]

def classify_support_sub(state: RouterState) -> RouterState:
    sub_classifier = llm.with_structured_output(SupportSubcategory)
    result = sub_classifier.invoke(state["message"])
    return {"sub_intent": result.subcategory}

def route_support(state) -> str:
    return state.get("sub_intent", "other")

# In the graph, after the top-level "support" node:
builder.add_conditional_edges("support", route_support, {
    "billing": "billing_handler",
    "technical": "technical_handler",
    "account": "account_handler",
    "other": "support_other",
})

def route(state: RouterState) -> str:
    # Explicit low-confidence fallback
    if state["confidence"] < 0.7:
        return "clarify"
    return state["intent"]

def handle_clarify(state: RouterState) -> RouterState:
    options = ["general question (FAQ)", "account or billing support", "upgrade or purchase"]
    opts_str = "\n".join(f"- {o}" for o in options)
    return {"response": f"I want to make sure I help you correctly. Are you asking about:\n{opts_str}"}

from langchain_core.messages import HumanMessage, AIMessage
from langgraph.graph import MessagesState

class RouterStateWithHistory(MessagesState):
    intent: str
    confidence: float
    response: str

def classify_with_history(state: RouterStateWithHistory) -> dict:
    # Include the last 4 turns as context
    history = state["messages"][-4:]
    history_text = "\n".join(
        f"{'User' if isinstance(m, HumanMessage) else 'Assistant'}: {m.content}"
        for m in history[:-1]  # exclude the current message
    )
    current = state["messages"][-1].content

    prompt = f"""Conversation so far:
{history_text}

Latest message: {current}

Classify the latest message's intent in context."""

    result = classifier.invoke(prompt)
    return {"intent": result.intent, "confidence": result.confidence}
